def encode(message):
    vowels = 'aeiou'
    result = ''
    for char in message:
        if char.isalpha():
            if char.lower() in vowels:
                index = vowels.index(char.lower())
                shifted = (index + 2) % 5
                new_char = vowels[shifted].upper() if char.isupper() else vowels[shifted]
                result += new_char
            else:
                result += char.swapcase()
        else:
            result += char
    return result
